 1	import type { FC } from 'react';
 2	import { DetailsItem } from 'src/components/DetailItems/DetailItem';
 3	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
 4	import { getProviderTypeIcon } from 'src/plans/details/utils/constants';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import LoadingSuspend from '@components/LoadingSuspend';
 8	import ProviderIconLink from '@components/ProviderIconLink';
 9	import { ProviderModelGroupVersionKind, type V1beta1Plan } from '@kubev2v/types';
10	import { DescriptionList } from '@patternfly/react-core';
11	import { getName, getNamespace } from '@utils/crds/common/selectors';
12	import { useIsDarkTheme } from '@utils/hooks/useIsDarkTheme';
13	
14	import usePlanSourceProvider from '../../../../hooks/usePlanSourceProvider';
15	import usePlanDestinationProvider from '../hooks/usePlanDestinationProvider';
16	
17	type ProvidersSectionProps = {
18	  plan: V1beta1Plan;
19	};
20	
21	const ProvidersSection: FC<ProvidersSectionProps> = ({ plan }) => {
22	  const { t } = useForkliftTranslation();
23	  const {
24	    loaded: sourceProviderLoaded,
25	    loadError: sourceProviderLoadError,
26	    sourceProvider,
27	  } = usePlanSourceProvider(plan);
28	  const {
29	    destinationProvider,
30	    loaded: destinationProviderLoaded,
31	    loadError: destinationProviderLoadError,
32	  } = usePlanDestinationProvider(plan);
33	  const sourceProviderName = getName(sourceProvider);
34	  const destinationProviderName = getName(destinationProvider);
35	  const isDarkTheme = useIsDarkTheme();
36	
37	  return (
38	    <LoadingSuspend
39	      obj={sourceProvider}
40	      loaded={sourceProviderLoaded && destinationProviderLoaded}
41	      loadError={sourceProviderLoadError ?? destinationProviderLoadError}
42	    >
43	      <DescriptionList
44	        columnModifier={{
45	          default: '2Col',
46	        }}
47	      >
48	        <DetailsItem
49	          title={t('Source provider')}
50	          content={
51	            <ProviderIconLink
52	              href={getResourceUrl({
53	                groupVersionKind: ProviderModelGroupVersionKind,
54	                name: sourceProviderName,
55	                namespace: getNamespace(sourceProvider),
56	              })}
57	              providerIcon={getProviderTypeIcon(sourceProvider?.spec?.type, isDarkTheme)}
58	              providerName={sourceProviderName}
59	            />
60	          }
61	          helpContent={t('source provider')}
62	          crumbs={['spec', 'providers', 'source']}
63	        />
64	
65	        <DetailsItem
66	          title={t('Target provider')}
67	          content={
68	            <ProviderIconLink
69	              href={getResourceUrl({
70	                groupVersionKind: ProviderModelGroupVersionKind,
71	                name: destinationProviderName,
72	                namespace: getNamespace(destinationProvider),
73	              })}
74	              providerIcon={getProviderTypeIcon(destinationProvider?.spec?.type, isDarkTheme)}
75	              providerName={destinationProviderName}
76	            />
77	          }
78	          helpContent={t('destination provider')}
79	          crumbs={['spec', 'providers', 'destination']}
80	        />
81	      </DescriptionList>
82	    </LoadingSuspend>
83	  );
84	};
85	
86	export default ProvidersSection;

